#include<bits/stdc++.h>
using namespace std;
int a[3005][3005];//a[i][j] == 1表示i手势能赢j手势 
int main()
{
	int n, m;
	cin >> n >> m;
	for(int i = 1; i <= n; i++){
		string s;
		cin >> s;
		for(int j = 1; j <= s.size(); j++){
			if(s[j - 1] == 'W')a[i][j] = 1;
			else if(s[j - 1] == 'L')a[j][i] = 1;
		}
	}
	for(int i = 1; i <= m; i++){
		int s1, s2;
		cin >> s1 >> s2;
		int cnt = 0;
		for(int j = 1; j <= n; j++){
			if(a[j][s1] && a[j][s2])cnt++;
		}
		cout << cnt * (n * 2 - cnt) << endl;
	}
}
